SELECT
wq.*,
u.username as userName,
p.name as petName
FROM warning_questionnaire wq
LEFT JOIN user u ON wq.user_id = u.id
LEFT JOIN pet p ON wq.pet_id = p.id


        AND wq.user_id = #{dto.userId}


        AND wq.status = #{dto.status}


        AND wq.pet_id = #{dto.petId}


ORDER BY wq.create_time DESC

    LIMIT #{dto.size} OFFSET #{dto.offset}

SELECT COUNT(*) FROM warning_questionnaire wq
LEFT JOIN user u ON wq.user_id = u.id
LEFT JOIN pet p ON wq.pet_id = p.id


        AND wq.user_id = #{dto.userId}


        AND wq.pet_id = #{dto.petId}


        AND wq.status = #{dto.status}


        AND wq.question_type = #{dto.questionType}


        AND wq.warning_level = #{dto.warningLevel}


        AND u.username LIKE CONCAT('%', #{dto.username}, '%')


        AND p.name LIKE CONCAT('%', #{dto.petName}, '%')

SELECT
wq.*,
u.username as userName,
u.phone,
p.name as petName,
p.cover as petAvatar
FROM warning_questionnaire wq
LEFT JOIN user u ON wq.user_id = u.id
LEFT JOIN pet p ON wq.pet_id = p.id

    AND wq.user_id = #{dto.userId}
    AND wq.pet_id = #{dto.petId}
    AND wq.status = #{dto.status}
    AND wq.question_type = #{dto.questionType}
    AND wq.warning_level = #{dto.warningLevel}

        AND u.username LIKE CONCAT('%', #{dto.username}, '%')


        AND p.name LIKE CONCAT('%', #{dto.petName}, '%')


ORDER BY wq.create_time DESC

    LIMIT #{dto.offset}, #{dto.size}

SELECT COUNT(*) > 0
FROM warning_questionnaire
WHERE user_id = #{userId}
  AND pet_id = #{petId}
  AND question_type = #{type}
  AND DATE_FORMAT(create_time, '%Y%m') = DATE_FORMAT(NOW(), '%Y%m')
